import 'package:flutter/material.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';


class LoginScreen extends StatefulWidget {
  @override
  _LoginScreenState createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> with SingleTickerProviderStateMixin{

  @override
  void initState(){
    super.initState();

    Timer(Duration(seconds: 2), () {
      Navigator.of(context).pushReplacement(MaterialPageRoute(builder: (context) => SplashScreen()));
    });
  }

  @override
  Widget build(BuildContext context){
    return Scaffold(
        appBar: AppBar(
          title: Text('Login Screen'),
        ),

        body: Center(
            child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children:[
                  _biometricButton()
                  SizedBox(height: 10),
                  _passwordButton(),
                ])
        )
    );
  }

  Widget _biometricButton(){

    return RaisedButton(
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(5)),

      child: Text('Biometrics'),
      onPressed: () async{

        final LocalAuthentication authentication = LocalAuthentication();

        try {

          final bool isAvailable = await authentication.isBiometricAuthSupported;
          final BiometricPrompt.PromptInfo promptInfo =
              BiometricPrompt.PromptInfo(
                  title: 'Authenticate',
                  description: 'You will be asked to authenticate with your fingerprint or Face ID',
                  negativeButtonTitle: 'Cancel');

          if (isAvailable) {
            authentication.authenticateBiometric(promptInfo).then((result){

              if(result == AuthenticationResult.success) {
                print('Authentication Successful!');

                final SharedPreferences prefs = await SharedPreferences.getInstance();

                prefs.setString("biometrics", "true");

                Navigator.of(context).pushReplacement(MaterialPageRoute(builder: (context) => SplashScreen()));
              } else{
                print('Authentication Failed');

              }
            });
          }
        } catch (e){

          print('Authentication Error: $e');

        }
      },
    );
  }

  Widget _passwordButton(){

    return RaisedButton(
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(5)),

      child: Text('Password'),
      onPressed: () async{
        final SharedPreferences prefs = await SharedPreferences.getInstance();

        if(prefs.getString("biometrics") == "true"){
          print('Biometric Authentication Already Enabled');

          Navigator.of(context).pushReplacement(MaterialPageRoute(builder: (context) => SplashScreen()));
        }else {
          Navigator.of(context).pushReplacement(MaterialPageRoute(builder: (context) => PasswordScreen()));
        }

      },
    );
  }
}


class PasswordScreen extends StatefulWidget{

  @override
  _PasswordScreenState createState() => _PasswordScreenState();
}

class _PasswordScreenState extends State<PasswordScreen> with SingleTickerProviderStateMixin {

  final TextEditingController username = TextEditingController(text: 'admin');
  final TextEditingController password = TextEditingController(text:'<PASSWORD>');


  @override
  void initState(){
    super.initState();

    Timer(Duration(seconds: 2), () {
      Navigator.of(context).pushReplacement(MaterialPageRoute(builder: (context) => SplashScreen()));
    });

  }

  @override
  Widget build(BuildContext context){
    return Scaffold(
        appBar: AppBar(
          title: Text('Password Screen'),
        ),

        body: Center(
            child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                crossAxisAlignment: CrossAxisAlignment.stretch,

                children:[
                  TextField(
                    controller: username,
                  ),

                  SizedBox(height: 10),

                  TextField(
                      controller: password,

                    ),

                  SizedBox(height: 15),

                  RaisedButton(
                    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(5)),

                    child: Text('Login'),
                    onPressed: () async{

                      final SharedPreferences prefs = await SharedPreferences.getInstance();

                      if (username.text == 'admin' && password.text == '<PASSWORD>') {
                        print("Authentication Successful!");

                        prefs.setString("biometrics", "false");

                        Navigator.of(context).pushReplacement(MaterialPageRoute(builder: (context) => SplashScreen()));
                      } else{
                        print("Authentication Failed! Try Again");

                      }
                    },
                  ),
                ])
        )
    );
  }
}


